import{_ as t,o as i,c as o,a2 as a}from"./chunks/framework.Bix3-HpO.js";const g=JSON.parse('{"title":"Widgets","description":"Kemoku Plugin - Widgets","frontmatter":{"title":"Widgets","description":"Kemoku Plugin - Widgets","weight":80,"extra":{"order":80},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/widgets"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/widgets"}],["meta",{"property":"og:title","content":"Widgets"}],["meta",{"property":"og:description","content":"Kemoku Plugin - Widgets"}],["meta",{"name":"twitter:title","content":"Widgets"}],["meta",{"name":"twitter:description","content":"Kemoku Plugin - Widgets"}]]},"headers":[],"relativePath":"docs/kemoku/widgets.md","filePath":"docs/kemoku/widgets.md"}'),s={name:"docs/kemoku/widgets.md"};function d(n,e,r,l,m,u){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="kemoku-plugin-widgets" tabindex="-1">Kemoku Plugin Widgets <a class="header-anchor" href="#kemoku-plugin-widgets" aria-label="Permalink to &quot;Kemoku Plugin Widgets&quot;">​</a></h1><p>There are 2 type of widgets available in the plugin.</p><hr><h3 id="blocks-as-widgets" tabindex="-1">Blocks as Widgets <a class="header-anchor" href="#blocks-as-widgets" aria-label="Permalink to &quot;Blocks as Widgets&quot;">​</a></h3><p>Since WordPress 5.8 update, blocks can be used as widgets, and that&#39;s the recommended way. Kemoku has been updated so that you can use blocks in widget areas. All widgets, including the ones that are intended for review pages only, can be used in widget areas. Check out plugin <a href="/docs/kemoku/blocks">blocks</a> for more information.</p><p>However, if for some reason you want to use legacy widgets, you still do so as described below.</p><h3 id="review-widgets" tabindex="-1">Review Widgets <a class="header-anchor" href="#review-widgets" aria-label="Permalink to &quot;Review Widgets&quot;">​</a></h3><p>Here are the widgets available in Kemoku plugin that you can use:</p><ul><li>Kemoku Review Widget</li><li>Kemoku Reviews Widget</li></ul><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-widgets.png" alt="kemoku-widgets"></p><p><code>💁 since version 1.0.8</code> you can choose to:</p><ul><li>display terms and conditions in full,</li><li>just a short notice</li><li>or skip them at all.</li></ul><h4 id="kemoku-review-widget" tabindex="-1">Kemoku Review Widget <a class="header-anchor" href="#kemoku-review-widget" aria-label="Permalink to &quot;Kemoku Review Widget&quot;">​</a></h4><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-review-widget.png" alt="kemoku-single-kemoku-review-widget"></p><h4 id="kemoku-reviews-widget" tabindex="-1">Kemoku Reviews Widget <a class="header-anchor" href="#kemoku-reviews-widget" aria-label="Permalink to &quot;Kemoku Reviews Widget&quot;">​</a></h4><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-widget.png" alt="kemoku-multiple-kemoku-reviews-widget"></p>',16)])])}const k=t(s,[["render",d]]);export{g as __pageData,k as default};
